INSERT INTO `v1_74b805e396769085a154cc715bfb6bf4efa721aeff718d76e747674fb43630eb` VALUES (110411, 19450021, 10, 0, 11, "どうしたんだ、ユイ？\nあいつのために\nわざわざ弁当作ってきたんだろ？\nとっとと誘えばいいじゃないか。", 0, 0, 945, 1, 1);
INSERT INTO `v1_74b805e396769085a154cc715bfb6bf4efa721aeff718d76e747674fb43630eb` VALUES (0, 19450022, "", "", 91, "", "", "", 945, "", "");
