INSERT INTO `v1_74b805e396769085a154cc715bfb6bf4efa721aeff718d76e747674fb43630eb` VALUES (122611, 19450033, 5, 0, 11, "…うん、やっちゃった…\nおっきなハートマーク…\nやっぱりこれは無しで！\nマコトちゃん食べてくれる！？", 0, 0, 945, 1, 1);
INSERT INTO `v1_74b805e396769085a154cc715bfb6bf4efa721aeff718d76e747674fb43630eb` VALUES (0, 19450034, "", "", 91, "", "", "", 945, "", "");
